using UnityEngine;
using UnityEngine.UI;
using System;
using System.Collections.Generic;

// PlayerStats.cs - Main player data holder
public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance;

    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 500;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float baseAttackDamage = 10f;
    public float attackMultiplier = 1.0f;
    public float defenseMultiplier = 1.0f;
    public float criticalChance = 0.05f;
    public float criticalMultiplier = 2.0f;
    public int armor = 0;
    public List<string> ownedItems = new List<string>();
    public string equippedWeapon = "Fists";
    public string equippedArmor = "None";

    public event Action<float, float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnPremiumCurrencyChanged;
    public event Action OnPlayerDied;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        LoadPlayerData();
    }

    public void TakeDamage(float rawDamage, DamageType damageType = DamageType.Physical)
    {
        float finalDamage = DamageCalculator.CalculateDamage(rawDamage, damageType, armor, defenseMultiplier);
        currentHealth -= finalDamage;
        currentHealth = Mathf.Clamp(currentHealth, 0f, maxHealth);

        OnHealthChanged?.Invoke(currentHealth, maxHealth);

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    public void Heal(float amount)
    {
        currentHealth += amount;
        currentHealth = Mathf.Clamp(currentHealth, 0f, maxHealth);
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public float DealDamage()
    {
        float damage = DamageCalculator.CalculatePlayerDamage(baseAttackDamage, attackMultiplier, criticalChance, criticalMultiplier);
        return damage;
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            OnCurrencyChanged?.Invoke(currency);
            SavePlayerData();
            return true;
        }
        return false;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        OnCurrencyChanged?.Invoke(currency);
        SavePlayerData();
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (premiumCurrency >= amount)
        {
            premiumCurrency -= amount;
            OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
            SavePlayerData();
            return true;
        }
        return false;
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
        SavePlayerData();
    }

    public void AddItem(string itemId)
    {
        if (!ownedItems.Contains(itemId))
        {
            ownedItems.Add(itemId);
            SavePlayerData();
        }
    }

    public bool HasItem(string itemId)
    {
        return ownedItems.Contains(itemId);
    }

    public void EquipWeapon(string weaponId)
    {
        equippedWeapon = weaponId;
        ShopItem item = ShopDatabase.Instance.GetItem(weaponId);
        if (item != null)
        {
            baseAttackDamage = 10f + item.statBonus;
            attackMultiplier = 1.0f + item.multiplierBonus;
        }
        SavePlayerData();
    }

    public void EquipArmor(string armorId)
    {
        equippedArmor = armorId;
        ShopItem item = ShopDatabase.Instance.GetItem(armorId);
        if (item != null)
        {
            armor = (int)item.statBonus;
            defenseMultiplier = 1.0f + item.multiplierBonus;
        }
        SavePlayerData();
    }

    public void LevelUp()
    {
        playerLevel++;
        maxHealth += 10f;
        currentHealth = maxHealth;
        baseAttackDamage += 2f;
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
        SavePlayerData();
    }

    private void Die()
    {
        OnPlayerDied?.Invoke();
    }

    public void Respawn()
    {
        currentHealth = maxHealth;
        OnHealthChanged?.Invoke(currentHealth, maxHealth);
    }

    public void SavePlayerData()
    {
        PlayerPrefs.SetFloat("MaxHealth", maxHealth);
        PlayerPrefs.SetFloat("CurrentHealth", currentHealth);
        PlayerPrefs.SetInt("Currency", currency);
        PlayerPrefs.SetInt("PremiumCurrency", premiumCurrency);
        PlayerPrefs.SetInt("PlayerLevel", playerLevel);
        PlayerPrefs.SetFloat("BaseAttackDamage", baseAttackDamage);
        PlayerPrefs.SetFloat("AttackMultiplier", attackMultiplier);
        PlayerPrefs.SetFloat("DefenseMultiplier", defenseMultiplier);
        PlayerPrefs.SetFloat("CriticalChance", criticalChance);
        PlayerPrefs.SetFloat("CriticalMultiplier", criticalMultiplier);
        PlayerPrefs.SetInt("Armor", armor);
        PlayerPrefs.SetString("EquippedWeapon", equippedWeapon);
        PlayerPrefs.SetString("EquippedArmor", equippedArmor);
        PlayerPrefs.SetString("OwnedItems", string.Join(",", ownedItems));
        PlayerPrefs.Save();
    }

    public void LoadPlayerData()
    {
        if (PlayerPrefs.HasKey("PlayerLevel"))
        {
            maxHealth = PlayerPrefs.GetFloat("MaxHealth", 100f);
            currentHealth = PlayerPrefs.GetFloat("CurrentHealth", 100f);
            currency = PlayerPrefs.GetInt("Currency", 500);
            premiumCurrency = PlayerPrefs.GetInt("PremiumCurrency", 0);
            playerLevel = PlayerPrefs.GetInt("PlayerLevel", 1);
            baseAttackDamage = PlayerPrefs.GetFloat("BaseAttackDamage", 10f);
            attackMultiplier = PlayerPrefs.GetFloat("AttackMultiplier", 1.0f);
            defenseMultiplier = PlayerPrefs.GetFloat("DefenseMultiplier", 1.0f);
            criticalChance = PlayerPrefs.GetFloat("CriticalChance", 0.05f);
            criticalMultiplier = PlayerPrefs.GetFloat("CriticalMultiplier", 2.0f);
            armor = PlayerPrefs.GetInt("Armor", 0);
            equippedWeapon = PlayerPrefs.GetString("EquippedWeapon", "Fists");
            equippedArmor = PlayerPrefs.GetString("EquippedArmor", "None");

            string itemsStr = PlayerPrefs.GetString("OwnedItems", "");
            if (!string.IsNullOrEmpty(itemsStr))
            {
                ownedItems = new List<string>(itemsStr.Split(','));
            }
        }
    }

    public void ResetData()
    {
        PlayerPrefs.DeleteAll();
        maxHealth = 100f;
        currentHealth = 100f;
        currency = 500;
        premiumCurrency = 0;
        playerLevel = 1;
        baseAttackDamage = 10f;
        attackMultiplier = 1.0f;
        defenseMultiplier = 1.0f;
        criticalChance = 0.05f;
        criticalMultiplier = 2.0f;
        armor = 0;
        ownedItems.Clear();
        equippedWeapon = "Fists";
        equippedArmor = "None";
    }
}

