public enum DamageType
{
    Physical,
    Magical,
    True,
    Fire,
    Ice,
    Poison
}

// DamageCalculator.cs - Client-side damage calculation
public static class DamageCalculator
{
    public static float CalculateDamage(float rawDamage, DamageType damageType, int armor, float defenseMultiplier)
    {
        float finalDamage = rawDamage;

        switch (damageType)
        {
            case DamageType.Physical:
                float armorReduction = armor / (armor + 100f);
                finalDamage = rawDamage * (1f - armorReduction) / defenseMultiplier;
                break;

            case DamageType.Magical:
                finalDamage = rawDamage / defenseMultiplier;
                break;

            case DamageType.True:
                finalDamage = rawDamage;
                break;

            case DamageType.Fire:
                finalDamage = rawDamage * 1.2f / defenseMultiplier;
                break;

            case DamageType.Ice:
                finalDamage = rawDamage * 0.9f / defenseMultiplier;
                break;

            case DamageType.Poison:
                finalDamage = rawDamage * 0.5f;
                break;
        }

        finalDamage = Mathf.Max(finalDamage, 1f);
        return Mathf.Round(finalDamage * 10f) / 10f;
    }

    public static float CalculatePlayerDamage(float baseDamage, float attackMultiplier, float critChance, float critMultiplier)
    {
        float damage = baseDamage * attackMultiplier;

        float randomVariance = UnityEngine.Random.Range(0.9f, 1.1f);
        damage *= randomVariance;

        if (UnityEngine.Random.value <= critChance)
        {
            damage *= critMultiplier;
        }

        return Mathf.Round(damage * 10f) / 10f;
    }

    public static float CalculateDPS(float baseDamage, float attackMultiplier, float critChance, float critMultiplier, float attackSpeed)
    {
        float avgDamage = baseDamage * attackMultiplier;
        float effectiveCritMultiplier = 1f + (critChance * (critMultiplier - 1f));
        avgDamage *= effectiveCritMultiplier;
        return avgDamage * attackSpeed;
    }
}

