[System.Serializable]
public class ShopItem
{
    public string itemId;
    public string itemName;
    public string description;
    public int basePrice;
    public int premiumPrice;
    public bool isPremiumOnly;
    public ItemCategory category;
    public ItemRarity rarity;
    public float statBonus;
    public float multiplierBonus;
    public Sprite icon;

    public int GetDiscountedPrice(float discountPercent)
    {
        return Mathf.RoundToInt(basePrice * (1f - discountPercent));
    }

    public int GetLevelScaledPrice(int playerLevel)
    {
        return Mathf.RoundToInt(basePrice * (1f + (playerLevel - 1) * 0.1f));
    }
}

